# ---------------------------------------------------------------------------

def _parse_qs_python(qs: str) -> dict[str, list[str]]:
    result: dict[str, list[str]] = {}
    if not qs:
        return result
    for part in qs.split("&"):
        if not part:
            continue
        if "=" in part:
            k, v = part.split("=", 1)
        else:
            k, v = part, ""
        k = unquote(k.replace("+", " "))
        v = unquote(v.replace("+", " "))
        result.setdefault(k, []).append(v)
    return result


