                            _k.encode("latin-1") if isinstance(_k, str) else _k,
                            _v.encode("latin-1") if isinstance(_v, str) else _v,
                        ))
                _di_sc = getattr(_sub, 'status_code', None)
                if _di_sc is not None and _di_sc != 200:
                    status_code = _di_sc
