                elif hasattr(_di_response_obj, "headers"):
                    for _k2, _v2 in _di_response_obj.headers.items():
                        _post_hdrs.append((
                            _k2.encode("latin-1") if isinstance(_k2, str) else _k2,
                            _v2.encode("latin-1") if isinstance(_v2, str) else _v2,
