async def _create_server(
    app: Any, host: str = "127.0.0.1", port: int = 8000,
    keep_alive_timeout: float = 30.0,
    root_path: str = "",
) -> asyncio.AbstractServer:
    """Create and return a C++ HTTP server without blocking.

    Used by ``run_server()`` and ``TestClient``. The caller is responsible
    for ``server.close()`` / ``server.wait_closed()``.
    """
    loop = asyncio.get_event_loop()
    core_app = app._core_app

    # Set server-level root_path
    global _server_root_path
    _server_root_path = root_path or getattr(app, 'root_path', '') or ''
    # Propagate root_path to app so OpenAPI schema includes it
    if _server_root_path and not getattr(app, 'root_path', ''):
        app.root_path = _server_root_path
    # Pre-add root_path to servers if root_path_in_servers is enabled and no explicit servers
    if _server_root_path and getattr(app, 'root_path_in_servers', True):
        _rp = _server_root_path.rstrip('/')
        _existing_servers = getattr(app, 'servers', []) or []
        _existing_urls = {s.get('url') for s in _existing_servers}
        # Only add root_path if no explicit servers are configured
        if _rp and _rp not in _existing_urls and not _existing_servers:
            if not hasattr(app, 'servers') or app.servers is None:
                app.servers = []
            app.servers.insert(0, {'url': _rp})
            # Invalidate cached schema
            app.openapi_schema = None
            app._openapi_bytes = None

    # Sync routes if not yet done
    if hasattr(app, "_sync_routes_to_core"):
        app._sync_routes_to_core()

    # OPT-A: Register app exception handlers for async dispatch paths
    _exc_handlers_all = dict(getattr(app, 'exception_handlers', {}))
    _set_app_exception_handlers(
        _exc_handlers_all,
        {k: v for k, v in _exc_handlers_all.items() if isinstance(k, int)},
    )
    # Register type-keyed handlers in C++ core for sync fast-path dispatch
    # Exclude default FastAPI handlers (http_exception_handler, request_validation_exception_handler)
    # so user-registered handlers take priority
    try:
        from fastapi.exception_handlers import (
            http_exception_handler as _default_http_handler,
            request_validation_exception_handler as _default_rv_handler,
        )
        _default_handlers = {_default_http_handler, _default_rv_handler}
    except ImportError:
        _default_handlers = set()
    _type_handlers = {k: v for k, v in _exc_handlers_all.items()
                      if isinstance(k, type) and v not in _default_handlers}
    if _type_handlers and hasattr(core_app, 'set_type_exception_handlers'):
        core_app.set_type_exception_handlers(_type_handlers)

    # Build WS app map for DI-wrapped WebSocket dispatch
    _build_ws_app_map(app)

    # Register @app.middleware("http") dispatch functions for async response path
    _http_dispatchers = []
    for _mw in getattr(app, 'user_middleware', []):
        _cls = getattr(_mw, 'cls', None) or (_mw[0] if isinstance(_mw, (list, tuple)) else None)
        _cls_name = getattr(_cls, '__name__', '')
        if _cls_name == 'BaseHTTPMiddleware':
            _kw = getattr(_mw, 'kwargs', {}) or {}
            _dispatch = _kw.get('dispatch')
            if _dispatch is not None:
                _http_dispatchers.append(_dispatch)
        elif _cls_name == 'GZipMiddleware':
            _kw = getattr(_mw, 'kwargs', {}) or {}
            _min_size = _kw.get('minimum_size', 500)
            _level = _kw.get('compresslevel', 9)
            def _make_gzip_dispatch(_min, _lvl):
                import gzip as _gzip
                async def _gzip_dispatch(request, call_next):
                    response = await call_next(request)
                    accept_enc = request.headers.get('accept-encoding', '')
                    if 'gzip' not in accept_enc:
                        return response
                    body = getattr(response, 'body', b'')
                    if not isinstance(body, bytes):
                        return response
                    if len(body) < _min:
                        return response
                    compressed = _gzip.compress(body, compresslevel=_lvl)
                    response.body = compressed
                    response.headers['content-encoding'] = 'gzip'
                    response.headers['content-length'] = str(len(compressed))
